fn lockfile_version_matches(prefix: &str, version: &str) -> bool {
    prefix == "latest" || strip_leading_v(version).starts_with(strip_leading_v(prefix))
}

fn strip_leading_v(version: &str) -> &str {
    version
        .strip_prefix('v')
        .or_else(|| version.strip_prefix('V'))
        .unwrap_or(version)
}

